<template>
	<div>
		<h2 class="h-title">่ฎก็ฎ้ขๅบ calculatedArea</h2>
		<div id="map" class="map-x"></div>
	</div>
</template>
<script>
import 'ol/ol.css';
import { Map, View } from 'ol';
import { Tile as TileLayer } from 'ol/layer';
import XYZ from 'ol/source/XYZ';
import { getLength, getArea } from 'ol/sphere';
import { fromLonLat } from 'ol/proj';
import VectorLayer from 'ol/layer/Vector';
import { Vector as VectorSource } from 'ol/source';
import { LineString } from 'ol/geom';
import Point from 'ol/geom/Point.js';
import { Style, Circle as CircleStyle, Fill, RegularShape, Stroke, Text } from 'ol/style';
import { Draw, Modify } from 'ol/interaction';

// ้ป่ฎคๅบ็กๆ ทๅผ
const style = new Style({
	fill: new Fill({
		color: 'rgba(255, 255, 255, 0.2)'
	}),
	stroke: new Stroke({
		color: 'rgba(0, 0, 0, 0.5)',
		lineDash: [10, 10],
		width: 2
	}),
	image: new CircleStyle({
		radius: 5,
		stroke: new Stroke({
			color: 'rgba(0, 0, 0, 0.7)'
		}),
		fill: new Fill({
			color: 'rgba(255, 255, 255, 0.2)'
		})
	})
});
// ็ป็นๆพ็คบ็ๆป้ฟๆ ทๅผ
const labelStyle = new Style({
	text: new Text({
		font: '14px Calibri,sans-serif',
		fill: new Fill({
			color: 'rgba(255, 255, 255, 1)'
		}),
		backgroundFill: new Fill({
			color: 'rgba(0, 0, 0, 0.7)'
		}),
		padding: [3, 3, 3, 3],
		textBaseline: 'bottom',
		offsetY: -15
	}),
	image: new RegularShape({
		radius: 8,
		points: 3,
		angle: Math.PI,
		displacement: [0, 10],
		fill: new Fill({
			color: 'rgba(0, 0, 0, 0.7)'
		})
	})
});
// ็บฟๆฎตไน้ดไธญ็นๆพ็คบ็้ฟๅบฆๆ ทๅผ
const segmentStyle = new Style({
	text: new Text({
		font: '12px Calibri,sans-serif',
		fill: new Fill({
			color: 'rgba(255, 255, 255, 1)'
		}),
		backgroundFill: new Fill({
			color: 'rgba(0, 0, 0, 0.4)'
		}),
		padding: [2, 2, 2, 2],
		textBaseline: 'bottom',
		offsetY: -12
	}),
	image: new RegularShape({
		radius: 6,
		points: 3,
		angle: Math.PI,
		displacement: [0, 8],
		fill: new Fill({
			color: 'rgba(0, 0, 0, 0.4)'
		})
	})
});
// ไฟฎๆนๆ็คบ่ฏญ็ๆ ทๅผ
const modifyStyle = new Style({
	image: new CircleStyle({
		radius: 5,
		stroke: new Stroke({
			color: 'rgba(0, 0, 0, 0.7)'
		}),
		fill: new Fill({
			color: 'rgba(0, 0, 0, 0.4)'
		})
	}),
	text: new Text({
		text: 'Drag to modify',
		font: '12px Calibri,sans-serif',
		fill: new Fill({
			color: 'rgba(255, 255, 255, 1)'
		}),
		backgroundFill: new Fill({
			color: 'rgba(0, 0, 0, 0.7)'
		}),
		padding: [2, 2, 2, 2],
		textAlign: 'left',
		offsetX: 15
	})
});
// ๆ็คบ่ฏญ็ๆ ทๅผ
const tipStyle = new Style({
	text: new Text({
		font: '12px Calibri,sans-serif',
		fill: new Fill({
			color: 'rgba(255, 255, 255, 1)'
		}),
		backgroundFill: new Fill({
			color: 'rgba(0, 0, 0, 0.4)'
		}),
		padding: [2, 2, 2, 2],
		textAlign: 'left',
		offsetX: 15
	})
});
export default {
	data() {
		return {
			map: null,
			draw: null,
			source: null,
			modify: null,
			tipPoint: null,
			// ็จไบๅฑ็คบๆ็คบ่ฏญ
			tip: '',
			// ็ปๅถไธญๆ็คบ่ฏญ
			activeTip: 'Click to continue drawing the polygon',
			// ๅๅงๆ็คบ่ฏญ
			idleTip: 'Click to start measuring'
		};
	},
	mounted() {
		this.initMap();
		this.initVector();
		this.initModify();
		this.addInteraction();
	},
	methods: {
		/**
		 * @description: ๅๅงๅๅฐๅพ
		 * @return {*}
		 */
		initMap() {
			this.map = new Map({
				target: 'map',
				layers: [
					new TileLayer({
						source: new XYZ({
							//้ป่ฒๅบๅพ
							url: 'http://map.geoq.cn/ArcGIS/rest/services/ChinaOnlineStreetPurplishBlue/MapServer/tile/{z}/{y}/{x}'
						}),
						visible: true
					})
				],
				view: new View({
					center: fromLonLat([116.39, 39.9]),
					zoom: 4
				})
			});
		},
		/**
		 * @description: ๅๅงๅ็ข้ๅพๅฑ
		 * @return {*}
		 */
		initVector() {
			this.source = new VectorSource();
			let vector = new VectorLayer({
				source: this.source,
				style: (feature) => {
					return this.styleFunction(feature);
				}
			});
			this.map.addLayer(vector);
		},
		/**
		 * @description: ๅๅงๅไฟฎๆนๅ่ฝ
		 * @return {*}
		 */
		initModify() {
			this.modify = new Modify({ source: this.source, style: modifyStyle });
			this.map.addInteraction(this.modify);
		},
		/**
		 * @description: ่ฎก็ฎ้ฟๅบฆ
		 * @param {*} line
		 * @return {*}
		 */
		formatLength(line) {
			const length = getLength(line);
			let output;
			if (length > 100) {
				output = Math.round((length / 1000) * 100) / 100 + ' km';
			} else {
				output = Math.round(length * 100) / 100 + ' m';
			}
			return output;
		},
		/**
		 * @description: ๆ นๆฎๅพๅฝข่ฎก็ฎ้ฟๅบฆ
		 * @param {*} line
		 * @return {*}
		 */
		formatArea(polygon) {
			const area = getArea(polygon);
			let output;
			if (area > 10000) {
				output = Math.round((area / 1000000) * 100) / 100 + ' km\xB2';
			} else {
				output = Math.round(area * 100) / 100 + ' m\xB2';
			}
			return output;
		},
		/**
		 * @description: ๆทปๅ ไบคไบ
		 * @return {*}
		 */
		addInteraction() {
			this.draw = new Draw({
				source: this.source,
				type: 'Polygon',
				style: (feature) => {
					return this.styleFunction(feature);
				}
			});
			// ๆ็คบ่ฏญ ๅๅงๅ
			this.tip = this.idleTip;
			this.draw.on('drawstart', (e) => {
				// ๅๅผๅง ไธๅ่ฎธไฟฎๆน
				this.modify.setActive(false);
				this.tip = this.activeTip;
			});
			// ็ปๅถๅฎๆฏ ไฟๅญๆๆ็ๅๆ ไฟกๆฏ
			this.draw.on('drawend', (e) => {
				// ่ฎพ็ฝฎไฟฎๆน็ๆ ทๅผ ๅจ็ป็น
				modifyStyle.setGeometry(this.tipPoint);
				// ็ปๅถๅฎๆฏ ๅ่ฎธไฟฎๆน
				this.modify.setActive(true);
				// ่ฎพ็ฝฎไฟฎๆน็ๆ ทๅผ ๅจๆๆฝ็น
				this.map.once('pointermove', function () {
					modifyStyle.setGeometry();
				});
				// ็ปๅถๅฎๆฏๆ็คบ่ฏญ ๅๅงๅ
				this.tip = this.idleTip;
				// ่ทๅ็ปๅถๅพๅฝข ๅๆ ไฟกๆฏ
				this.sktch = e.feature;
				let arr = this.sktch.getGeometry().getCoordinates()[0];
				for (let i = 0; i < arr.length - 1; i++) {
					let line = new LineString([arr[i], arr[i + 1]]);
					console.log('ๅๆ ่ฏฆๆ', arr[i], arr[i + 1], this.formatLength(line), this.formatArea(this.sktch.getGeometry()));
				}
			});
			this.modify.setActive(true);
			this.map.addInteraction(this.draw);
		},
		/**
		 * @description: ๅจๆๆพ็คบ ่ท็ฆป
		 * @param {*} feature
		 * @return {*}
		 */
		styleFunction(feature) {
			// ๅๅงๅๆ ทๅผ ๆๅ้่ฆ่ฟๅ ็ฑปๅ ๆฐ็ป
			let styles = [style];
			// ไธญ็นๆ ทๅผๅๅงๅ ไธ่ฌๅชๅๆฐ็ปไธญ็ไธไธช
			let segmentStyles = [segmentStyle];
			// ่ทๅๅพๅฝข
			const geometry = feature.getGeometry();
			// ่ทๅ็ฑปๅ
			const type = geometry.getType();
			// ้ๅฏน้ฟๅบฆ
			if (type === 'Polygon') {
				// ่ทๅๅ้จ็น
				let point = geometry.getInteriorPoint();
				// ่ทๅ้ข็งฏ
				let output = this.formatArea(geometry);
				// ๅฐ็ป็นๆ ทๅผ่ฎพ็ฝฎๅฐๅฏนๅบ็็ป็น
				labelStyle.setGeometry(point);
				// ็ป็นๆ ทๅผ็ๅฑ็คบๆๆฌไฟฎๆน
				labelStyle.getText().setText(output);
				// ๆทปๅ ๅฐๆ ทๅผๆฐ็ปไธญ
				styles.push(labelStyle);
				// ไธบๅฝๅๅพๅฝข็ๆฏๆก็บฟๆฎต็ไธญ็น่ฎพ็ฝฎๆ ทๅผ
				let count = 0;
				let line1 = new LineString(geometry.getCoordinates()[0]);
				line1.forEachSegment((start, end) => {
					let line = new LineString([start, end]);
					let output = this.formatLength(line);
					if (output == '0 m') {
						return styles;
					}
					if (segmentStyles.length - 1 < count) {
						// ็บฟๆฎตไน้ด็้ฟๅบฆๆพ็คบ
						// ๆทปๅ ไธไธช็บฟๆฎตๆ ทๅผ
						segmentStyles.push(segmentStyle.clone());
					}
					// ๅๅปบ็บฟๆฎตไธญ็น
					let segmentPoint = new Point(line.getCoordinateAt(0.5));
					// ็ปไธญ็น่ฎพ็ฝฎๆ ทๅผ
					segmentStyles[count].setGeometry(segmentPoint);
					// ไธญ็นๆ ทๅผไฟฎๆนๆๆฌ
					segmentStyles[count].getText().setText(output);
					// ๆทปๅ ๅฐๆ ทๅผๆฐ็ปไธญ
					styles.push(segmentStyles[count]);
					// ็บฟๆฎตๆฐ+1
					count++;
				});
			} else if (
				type === 'Point' &&
				!this.modify.getOverlay().getSource().getFeatures().length
			) {
				this.tipPoint = geometry;
				tipStyle.getText().setText(this.tip);
				styles.push(tipStyle);
			}
			return styles;
		}
	}
};
</script>
